import os
import re

# Mapping from placeholder patterns to replacement values
# All complex types (interfaces, abstract classes) use null
# Simple primitives use literal values
REPLACEMENTS = {
    r'\[URL url\]': 'null',
    r'\[URL\[\] urls\]': 'new java.net.URL[0]',
    r'\[boolean delegateToCLR\]': 'true',
    r'\[Boolean registrationDone\]': 'Boolean.TRUE',
    r'\[ClassLoader parent\]': 'null',
    r'\[ClassLoaderRepository clr\]': 'null',
    r'\[MBeanServer server\]': 'null',
    r'\[MLetContent mlet\]': 'null',
    r'\[ObjectInput in\]': 'null',
    r'\[ObjectName name\]': 'null',
    r'\[ObjectOutput out\]': 'null',
    r'\[String jarfile\]': '"test.jar"',
    r'\[String libdir\]': '"lib"',
    r'\[String libname\]': '"testlib"',
    r'\[String name\]': '"test"',
    r'\[String url\]': '"http://localhost/"',
    r'\[String version\]': '"1.0"',
    r'\[URL codebase\]': 'null',
    r'\[URLStreamHandlerFactory factory\]': 'null',
}

# Package and import header for correct tests
CORRECT_HEADER = """package mlet.tests.correct;

import javax.management.MBeanServer;
import javax.management.ObjectName;
import javax.management.loading.MLet;
import javax.management.loading.MLetContent;
import javax.management.loading.ClassLoaderRepository;
import java.net.URL;
import java.net.URLStreamHandlerFactory;
import java.io.ObjectInput;
import java.io.ObjectOutput;
"""

# Package and import header for incorrect tests
INCORRECT_HEADER = """package mlet.tests.incorrect;

import javax.management.MBeanServer;
import javax.management.ObjectName;
import javax.management.loading.MLet;
import javax.management.loading.MLetContent;
import javax.management.loading.ClassLoaderRepository;
import java.net.URL;
import java.net.URLStreamHandlerFactory;
import java.io.ObjectInput;
import java.io.ObjectOutput;
"""

base_dir = '/home/barista/agentic_barista/runs/synthesize/mlet/run_3/mlet/tests'

for subdir in ['correct', 'incorrect']:
    dirpath = os.path.join(base_dir, subdir)
    header = CORRECT_HEADER if subdir == 'correct' else INCORRECT_HEADER
    for fname in sorted(os.listdir(dirpath)):
        if not fname.endswith('.java'):
            continue
        fpath = os.path.join(dirpath, fname)
        with open(fpath, 'r') as f:
            content = f.read()

        # Replace the package line and add imports
        # The files start with "package mlet.tests.correct;" or similar
        # We replace it with our full header
        content = re.sub(r'^package mlet\.tests\.(correct|incorrect);', header.strip(), content, count=1)

        # Replace all placeholders
        for pattern, replacement in REPLACEMENTS.items():
            content = re.sub(pattern, replacement, content)

        # Fix MLet import - MLet class itself is used without import
        # The class reference "MLet" needs to be fully qualified or imported
        # It's already imported in the header, so just ensure the class is used correctly

        with open(fpath, 'w') as f:
            f.write(content)
        print(f"Processed {fname}")

print("Done!")
PYEOF
python3 /tmp/fill_placeholders.py

